INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5bd020f9-bcf8-404f-a366-2c0dae8ee0ef', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('84e314ac-4d36-41da-911b-9eb00173a757', $q$Managed Postgres Database$q$, $q$Every project provisions a dedicated Postgres instance with full SQL access, foreign keys, and support for 40+ extensions.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('84e314ac-4d36-41da-911b-9eb00173a757', $q$Auto-generated REST and GraphQL APIs$q$, $q$APIs are generated directly from the database schema, so tables and views are instantly queryable from client applications.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('84e314ac-4d36-41da-911b-9eb00173a757', $q$Authentication$q$, $q$Built-in user management supporting email/password, magic links, phone OTP, and 20+ social login providers.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('84e314ac-4d36-41da-911b-9eb00173a757', $q$Row Level Security$q$, $q$Fine-grained access control policies are defined in Postgres itself, letting teams secure data at the row level.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('84e314ac-4d36-41da-911b-9eb00173a757', $q$Storage$q$, $q$S3-compatible object storage with a global CDN, resumable uploads, and on-the-fly image transformations.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('84e314ac-4d36-41da-911b-9eb00173a757', $q$Edge Functions$q$, $q$Serverless TypeScript/Deno functions with Node.js compatibility that run close to users worldwide.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('84e314ac-4d36-41da-911b-9eb00173a757', $q$Realtime$q$, $q$WebSocket-based broadcast, presence, and database change listeners for building live, collaborative features.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('84e314ac-4d36-41da-911b-9eb00173a757', $q$Vector/AI toolkit$q$, $q$Built-in pgvector support for storing and querying embeddings alongside relational data for AI and search applications.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('84e314ac-4d36-41da-911b-9eb00173a757', $q$CLI and local development$q$, $q$A command-line interface for local development, schema migrations, type generation, and CI/CD workflows.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('84e314ac-4d36-41da-911b-9eb00173a757', $q$Database webhooks$q$, $q$Trigger HTTP calls to external services automatically in response to database table events.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('84e314ac-4d36-41da-911b-9eb00173a757', $q$Open source with self-hosting available, avoiding vendor lock-in$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('84e314ac-4d36-41da-911b-9eb00173a757', $q$Generous free tier and transparent, predictable core pricing on paid plans$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('84e314ac-4d36-41da-911b-9eb00173a757', $q$Full Postgres power (SQL, extensions, foreign keys) rather than a proprietary data model$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('84e314ac-4d36-41da-911b-9eb00173a757', $q$Auth, storage, realtime, and edge functions are bundled, reducing the number of vendors needed$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('84e314ac-4d36-41da-911b-9eb00173a757', $q$Fast initial setup with an approachable dashboard and strong developer tooling$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('84e314ac-4d36-41da-911b-9eb00173a757', $q$Usage-based overage billing for egress, compute, and active users can be hard to forecast at scale$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('84e314ac-4d36-41da-911b-9eb00173a757', $q$Free-tier projects automatically pause after a week of inactivity$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('84e314ac-4d36-41da-911b-9eb00173a757', $q$Community-only support on Free and Pro plans can mean slower help for non-critical issues$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('84e314ac-4d36-41da-911b-9eb00173a757', $q$Requires comfort with SQL and relational database concepts compared to simpler BaaS tools$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('84e314ac-4d36-41da-911b-9eb00173a757', $q$Newer platform overall than long-established competitors like Firebase or AWS Amplify$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('84e314ac-4d36-41da-911b-9eb00173a757', $q$Is Supabase free to use?$q$, $q$Yes, Supabase offers a free plan with 500 MB database storage, 50,000 monthly active users, and core features, though projects pause automatically after a week of inactivity.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('84e314ac-4d36-41da-911b-9eb00173a757', $q$What is Supabase used for?$q$, $q$Supabase is used as a backend for web and mobile apps, providing a managed Postgres database, authentication, file storage, realtime data sync, serverless functions, and vector search for AI features.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('84e314ac-4d36-41da-911b-9eb00173a757', $q$Is Supabase open source?$q$, $q$Yes, Supabase's core components are open source, and the entire stack can be self-hosted via Docker instead of using the hosted cloud service.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('84e314ac-4d36-41da-911b-9eb00173a757', $q$Can I self-host Supabase?$q$, $q$Yes, Supabase provides Docker-based self-hosting instructions for teams that want to run the full stack on their own infrastructure rather than using the managed cloud offering.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('84e314ac-4d36-41da-911b-9eb00173a757', $q$How does Supabase pricing work?$q$, $q$Supabase charges a flat monthly fee per organization tier (Free, Pro, Team, Enterprise) plus usage-based overage charges for compute, database egress, storage, and monthly active users beyond each plan's included allowances.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('84e314ac-4d36-41da-911b-9eb00173a757', $q$MVP and startup backend$q$, $q$Founders can launch a working backend with database, auth, and APIs in a single afternoon without hiring backend engineers first.$q$, $q$Solo founders and early-stage startups$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('84e314ac-4d36-41da-911b-9eb00173a757', $q$AI applications with embeddings$q$, $q$Teams store and query vector embeddings alongside relational data using pgvector, powering semantic search and RAG features without a separate vector database.$q$, $q$AI product teams and developers building LLM-powered apps$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('84e314ac-4d36-41da-911b-9eb00173a757', $q$Mobile app backend$q$, $q$Apps use Supabase Auth, Storage, and Realtime together to handle sign-in, media uploads, and live data sync across iOS and Android clients.$q$, $q$Mobile app development teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('84e314ac-4d36-41da-911b-9eb00173a757', $q$Enterprise Postgres consolidation$q$, $q$Larger organizations migrate scattered services onto a single compliant Postgres-based platform with SLAs and dedicated support.$q$, $q$Enterprises and platform teams standardizing on Postgres$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('84e314ac-4d36-41da-911b-9eb00173a757', $q$Free$q$, $q$$0$q$, $q$Monthly$q$, $q$["2 active projects","500 MB database storage","50,000 monthly active users","5 GB egress and 1 GB file storage","Community support only","Projects pause after 7 days of inactivity"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('84e314ac-4d36-41da-911b-9eb00173a757', $q$Pro$q$, $q$$25/month$q$, $q$Monthly$q$, $q$["100,000 monthly active users included","8 GB database disk size","250 GB egress and 100 GB file storage","$10/month compute credit included","Daily backups retained for 7 days","Email support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('84e314ac-4d36-41da-911b-9eb00173a757', $q$Team$q$, $q$$599/month$q$, $q$Monthly$q$, $q$["SOC2 and ISO 27001 compliance","Daily backups retained for 14 days","28-day log retention","Priority email support with SLAs","$10/month compute credit included"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('84e314ac-4d36-41da-911b-9eb00173a757', $q$Enterprise$q$, $q$Custom$q$, $q$Custom$q$, $q$["Designated support manager","Uptime SLAs","24x7x365 premium support","Bring Your Own Cloud option","HIPAA compliance available"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('84e314ac-4d36-41da-911b-9eb00173a757', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Supabase is an open-source backend-as-a-service platform built around Postgres, marketed as an alternative to Firebase. Founded in 2020 and incubated through Y Combinator, it bundles a managed Postgres database with auto-generated REST and GraphQL APIs, authentication, file storage, realtime subscriptions, serverless edge functions, and a vector store for AI applications into a single dashboard-driven workflow.$q$, $q$Because every project is a full Postgres database, teams get SQL, foreign keys, Row Level Security, and dozens of extensions instead of a proprietary NoSQL layer, while still keeping the 'spin up a backend in minutes' experience typically associated with Firebase. Supabase can be used as a hosted cloud service or self-hosted via Docker, which helps teams avoid vendor lock-in.$q$, $q$The company has raised venture funding and now serves both small independent developers and larger organizations running production workloads across multiple global regions, with SOC2 and ISO 27001 compliance available on its higher-tier plans.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('84e314ac-4d36-41da-911b-9eb00173a757', $q$who-supabase-is-for$q$, $q$Who Supabase Is For$q$, 2, ARRAY[$q$Supabase suits developers who already think in SQL and want a managed Postgres database without manually wiring up authentication, storage, and APIs. Solo founders and small teams building MVPs benefit from the generous free tier and instant REST and GraphQL endpoints generated directly from the database schema.$q$, $q$It also fits teams building AI-powered products, since pgvector is built in, letting them store embeddings alongside relational data rather than running a separate vector database. Agencies and startups that want to avoid vendor lock-in appreciate that the entire stack is open source and can be self-hosted if requirements change later.$q$, $q$Larger organizations that need compliance certifications, dedicated support, and predictable scaling also use Supabase, particularly when they want to consolidate database, auth, storage, and background functions under one provider rather than stitching together several separate services.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('84e314ac-4d36-41da-911b-9eb00173a757', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Teams with little SQL or relational-database experience who want a pure document store may find Firestore's or MongoDB's data model more natural than working within Postgres's relational constraints and schema design requirements.$q$, $q$Projects with unpredictable, spiky usage should budget carefully: overage billing for egress, compute, and monthly active users can make costs harder to forecast than a flat-rate competitor, especially once a project outgrows the free tier's limits and its automatic pausing after inactivity.$q$, $q$Organizations wanting a completely hands-off, zero-infrastructure experience with no exposure to database concepts such as connection pooling or read replicas may find Supabase still requires more backend literacy than a pure no-code app builder.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('84e314ac-4d36-41da-911b-9eb00173a757', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, Supabase provisions a dedicated Postgres instance per project and layers on auto-generated REST and GraphQL APIs, so any table or view is immediately queryable from a client app without writing boilerplate backend code. Row Level Security policies let teams enforce fine-grained access control directly in the database.$q$, $q$Around that database sit purpose-built modules: Auth handles email/password, magic links, phone OTP, and 20+ social logins; Storage offers S3-compatible object storage with a global CDN and image transformations; Edge Functions run serverless TypeScript/Deno code close to users; and Realtime streams database changes, presence, and broadcast messages over WebSockets.$q$, $q$For AI use cases, the Vector toolkit uses pgvector to store and query embeddings inside the same Postgres database, removing the need for a separate vector store. A dedicated CLI, local development environment, and database webhooks round out the toolkit for teams that want to script migrations and CI/CD around their schema.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('84e314ac-4d36-41da-911b-9eb00173a757', $q$the-supabase-experience$q$, $q$The Supabase Experience$q$, 2, ARRAY[$q$New users can spin up a project from the dashboard in under a minute, get a working Postgres instance with a visual table editor, SQL editor, and API documentation generated automatically for their schema. This makes the first hour with Supabase feel closer to a no-code tool than a traditional cloud database console.$q$, $q$As projects mature, the developer experience extends to a CLI for local development, schema migrations, and type generation, plus GitHub-based deployment workflows, so teams are not stuck clicking through a dashboard once they move past prototyping. Documentation is extensive and the product ships frequent feature updates.$q$, $q$Support is tiered: free and Pro users rely mainly on community channels like Discord and GitHub Discussions, while Team and Enterprise customers get priority email support and SLAs. Overall, most reviews describe the experience as fast to start with and genuinely powerful once a team invests in learning its Postgres foundations.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('84e314ac-4d36-41da-911b-9eb00173a757', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
