INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('84e314ac-4d36-41da-911b-9eb00173a757', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$150+ Data Source Connectors$q$, $q$Pulls data from a large catalog of advertising, analytics, SEO, social, ecommerce, and CRM platforms, including Google Ads, Meta Ads, LinkedIn Ads, GA4, HubSpot, and Salesforce.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$Multiple Reporting Destinations$q$, $q$Sends data to Looker Studio, Google Sheets, Excel, and Power BI, so teams can keep reporting in the tools they already use.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$Data Warehouse Sync$q$, $q$Loads marketing data into BigQuery, Snowflake, or Amazon Redshift for teams centralizing analytics beyond spreadsheets and dashboards.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$Scheduled Automated Refreshes$q$, $q$Runs data refreshes on a set cadence, from weekly on entry plans up to hourly on higher tiers, removing manual re-exports.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$Pre-Built Templates & Dashboards$q$, $q$Provides ready-made report templates and charts for common marketing reporting scenarios to speed up setup.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$Custom & Calculated Fields$q$, $q$Lets users blend and transform metrics across channels with custom formulas rather than relying only on raw platform metrics.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$AI-Assisted Data Queries$q$, $q$Includes monthly AI credits on every plan to help users query, summarize, and explore data using natural language.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$API Access$q$, $q$Offers API access for building custom or white-labeled data products on top of Supermetrics' connector infrastructure.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$Team & Account Management$q$, $q$Supports multiple users and multiple accounts per data source, with controls suited to agencies managing several clients.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$Extremely broad connector library covering nearly every major marketing, ad, and sales platform$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$Flexible delivery into popular BI tools, spreadsheets, and data warehouses without heavy custom engineering$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$Saves significant manual reporting time for agencies and teams managing many accounts$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$Established, mature product with a long track record in the marketing reporting space$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$Scales from spreadsheet-level reporting up to full data warehousing for growing data needs$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$Pricing structure is complex, driven by data sources, accounts, users, and destinations together$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$No free plan, and no month-to-month billing option, only annual commitments$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$Costs can escalate quickly for agencies with many client accounts and data sources$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$Some data warehousing and advanced reporting capabilities are gated to higher-priced tiers or add-ons$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$Building custom calculated metrics and complex cross-channel reports has a learning curve$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$Does Supermetrics offer a free plan?$q$, $q$No, Supermetrics does not have a free plan. It offers a 14-day free trial with no credit card required, after which a paid annual plan is required to continue.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$What data sources does Supermetrics support?$q$, $q$Supermetrics supports 150-plus data sources across paid advertising, organic social, SEO, web analytics, ecommerce, and CRM platforms, including Google Ads, Meta Ads, LinkedIn Ads, GA4, HubSpot, and Salesforce.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$Where can Supermetrics send data?$q$, $q$Data can be delivered to reporting destinations such as Looker Studio, Google Sheets, Excel, and Power BI, or synced into data warehouses like BigQuery, Snowflake, and Amazon Redshift.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$Is Supermetrics billed monthly or annually?$q$, $q$Plans are shown with both monthly and annual pricing, but all subscriptions require an annual commitment rather than true month-to-month billing.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$Who founded Supermetrics and when?$q$, $q$Supermetrics was founded in 2013 in Helsinki, Finland, by Mikael Thuneberg, after he built an early script connecting the Google Analytics API to Excel.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$Agency Client Reporting$q$, $q$Consolidates ad and analytics performance data from many client accounts into scheduled, automatically refreshed reports, cutting down manual export work.$q$, $q$Marketing and digital agencies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$Cross-Channel Marketing Dashboards$q$, $q$Blends data from paid, organic, and analytics sources into a single Looker Studio, Sheets, or Power BI dashboard for ongoing campaign tracking.$q$, $q$In-house marketing teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$Marketing Data Warehousing$q$, $q$Syncs raw marketing data into BigQuery, Snowflake, or Redshift so it can be joined with other business data for deeper analysis.$q$, $q$Data and analytics teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$Automated Executive Reporting$q$, $q$Keeps recurring performance summaries and templated dashboards current without manual rebuilding before each review cycle.$q$, $q$Marketing leadership and executives$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$Starter$q$, $q$€39/month (billed annually) or €49/month billed monthly$q$, $q$Annual or monthly$q$, $q$["1 core destination","3 data sources","1 user","3 accounts per data source","Weekly data refreshes","4,000 monthly AI credits","Limited API access (50,000 rows/month)"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$Growth$q$, $q$€159/month (billed annually) or €199/month billed monthly$q$, $q$Annual or monthly$q$, $q$["1 core destination","7 data sources","2 users","7 accounts per data source","Daily data refreshes","12,000 monthly AI credits","1 custom data import configuration"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$Pro$q$, $q$€399/month (billed annually) or €499/month billed monthly$q$, $q$Annual or monthly$q$, $q$["1 core destination","10 data sources","3 users","10 accounts per data source","Hourly data refreshes","18,000 monthly AI credits","Supermetrics Storage Basic add-on available"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$Enterprise$q$, $q$Custom quote$q$, $q$Annual$q$, $q$["Unlimited data sources and users","On-demand data refreshes","Custom AI credits","Full data warehousing access","Enterprise-grade support and collaboration"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Supermetrics is a marketing data integration platform that automates the process of pulling performance data out of advertising, analytics, SEO, social, and sales platforms and pushing it into the dashboards, spreadsheets, and data warehouses teams already use for reporting. The company was founded in Helsinki, Finland, in 2013 by Mikael Thuneberg, after he built the first script to connect the Google Analytics API to Excel as a working analyst. That original idea, automating a manual export-and-paste workflow, remains the core of the product today, just expanded across 150-plus data sources.$q$, $q$In practice, Supermetrics works as a library of connectors: you authenticate a data source such as Google Ads, Meta Ads, LinkedIn Ads, GA4, HubSpot, or Salesforce, choose a destination such as Looker Studio, Google Sheets, Excel, Power BI, or a data warehouse like BigQuery or Snowflake, and set a refresh schedule. From there the platform keeps the data flowing without repeated manual exports, which is the problem it was originally built to solve for agencies and in-house marketers juggling many accounts.$q$, $q$Over more than a decade, Supermetrics has grown from a bootstrapped Excel add-in into a venture-backed data operations company, raising funding from investors including OpenOcean, Highland Europe, and IVP, and expanding into ELT and data warehousing for teams whose reporting needs outgrow spreadsheets and BI connectors. Its 2025 acquisition of Relay42 signaled a push toward customer data activation on top of its core reporting and pipeline business.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$who-supermetrics-is-for$q$, $q$Who Supermetrics Is For$q$, 2, ARRAY[$q$Supermetrics fits marketing agencies that report on multiple clients' ad and analytics performance and need a repeatable way to pull data from many accounts without manual CSV exports. It also suits in-house marketing and growth teams running campaigns across several ad platforms and analytics tools who want a single, automatically refreshed view instead of stitching numbers together by hand each week.$q$, $q$It is also a good match for data and analytics teams that already rely on Looker Studio, Power BI, Excel, or Google Sheets for reporting and simply need reliable, scheduled connectors feeding those tools, rather than a team of engineers maintaining custom API integrations for each platform.$q$, $q$Larger organizations moving toward centralized marketing data warehousing are another strong fit, since Supermetrics offers ELT-style syncing into BigQuery, Snowflake, and Redshift for teams that want raw, blended marketing data available for deeper analysis alongside other business data.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Solo marketers or very small businesses tracking only one or two channels on a tight budget may find Supermetrics more tool than they need. There is no free plan, only a 14-day trial, and pricing is driven by the number of data sources, accounts per source, users, and the destination in use, which can make even the entry Starter tier feel like overkill for a single-channel setup.$q$, $q$Teams that want month-to-month flexibility should also be cautious, since Supermetrics plans are sold on annual commitments rather than pay-as-you-go billing, which is a mismatch for short-term projects or teams still validating whether automated reporting is worth the spend.$q$, $q$Agencies with a large number of client accounts and data sources can also see costs climb quickly, since each additional source, account, or user typically adds to the bill. Organizations with in-house engineering capacity that would rather build and own custom pipelines to their warehouse may also find a narrower, cheaper tool a better fit than a broad, general-purpose connector platform.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, Supermetrics offers a large library of connectors spanning paid ads, organic social, SEO, web analytics, ecommerce, and CRM platforms, letting teams centralize data that would otherwise live in separate logins and exports. Alongside connectors, it supports multiple reporting destinations, including Looker Studio, Google Sheets, Excel, Power BI, and data warehouses such as BigQuery, Snowflake, and Amazon Redshift, so teams can keep using the visualization or storage layer they already prefer.$q$, $q$Scheduling and automation sit underneath all of this: refreshes can run on intervals from weekly up to hourly depending on plan, removing the need to manually re-pull data before every report. The platform also includes pre-built templates and dashboards for common reporting scenarios, calculated and custom fields for blending metrics across channels, and account and user management controls for agencies and teams managing access across clients.$q$, $q$More recently, Supermetrics has layered in AI-assisted capabilities, exposed through monthly AI credits on each plan, aimed at helping users query and summarize data with natural language rather than manually building every report. API access is also available for teams or partners building custom, white-labeled data products on top of Supermetrics' connector infrastructure.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a2099be2-0fe5-4bea-8970-af25479c0e1a', $q$the-supermetrics-experience$q$, $q$The Supermetrics Experience$q$, 2, ARRAY[$q$Getting started with Supermetrics generally means picking a destination first, since the product is organized around delivering data into a tool you already use, then connecting the specific data sources relevant to your reporting. Authentication is handled through each platform's own login, and most users can get a first connector delivering data within a single setup session, which is consistent with the product's original goal of removing manual export work rather than adding a new reporting surface to learn.$q$, $q$The overall experience is that of an infrastructure layer rather than a standalone analytics app: once configured, most of the day-to-day value comes from not having to think about it, as scheduled refreshes keep dashboards and spreadsheets current in the background. Where users tend to spend more active time is in structuring custom and calculated fields to blend metrics across channels consistently, and in navigating the pricing structure, which scales along several dimensions at once.$q$, $q$Compared with lighter-weight alternatives such as Windsor.ai or Whatagraph, or fuller reporting suites like Funnel.io, Supermetrics is often chosen for the sheer breadth of its connector catalog and its long track record, while some prospective buyers weigh its annual-only, multi-dimensional pricing against simpler flat-rate competitors before committing.$q$]::text[], 4);
