INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$Content Editor$q$, $q$Scores drafts in real time against top-ranking pages, highlighting missing terms, structural gaps, and length issues as you write or paste content.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$SERP Analyzer$q$, $q$Breaks down the search results for any keyword, surfacing content structure, common searcher questions, and backlink signals from top-ranking pages.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$Keyword Research$q$, $q$Finds related keywords and search volume localized by country, with a built-in clipboard to collect target terms without loading content into the editor.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$Content Audit$q$, $q$Compares an existing published page against a target keyword to flag word count, term usage, and internal linking gaps that hurt rankings.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$AI Visibility Tracker$q$, $q$Monitors how often and how a brand is cited in AI Overviews and chatbot answers across platforms like ChatGPT and Gemini, alongside traditional rank tracking.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$Surfer AI$q$, $q$Generates full draft articles from a content brief, ready for human review and refinement inside the Content Editor.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$Content Planning$q$, $q$Maps clusters of related topics and articles to guide a site's broader content strategy rather than optimizing one page at a time.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$Surfy AI Assistant$q$, $q$An in-app assistant that helps interpret SEO data and guides users through the platform's growing set of tools.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$CMS Integrations$q$, $q$Connects with WordPress and Google Docs so optimized content can be published or edited without leaving existing workflows.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$Internal Linking and Gap Analysis$q$, $q$Available on higher-tier plans, suggests internal links and highlights content coverage gaps across an entire site.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$Data-driven content scoring gives writers concrete, benchmarked guidance instead of generic SEO advice$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$Combines classic content optimization with newer AI-visibility tracking in a single subscription$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$Strong fit for agencies, with multiple workspaces and, on higher tiers, white-labeling and API access$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$Mature, well-documented product with an active user community built up since its 2017 launch$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$Direct integrations with WordPress and Google Docs fit the tool into existing publishing workflows$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$No perpetual free plan, and costs can add up quickly if usage exceeds a plan's document or AI prompt limits$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$Core NLP-based content scoring is strongest only in English, Danish, Dutch, and Polish$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$The 2025 rebrand to Positive Surfer under Positive Group has caused some naming and positioning confusion for longtime users$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$Content scores can encourage writers to chase a number rather than focus purely on reader value$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$The entry-level Discovery plan has modest document and page-tracking limits, so active teams often need to upgrade quickly$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$Is Surfer SEO still called Surfer SEO?$q$, $q$The company was acquired by Positive Group in late 2025 and rebranded to "Positive Surfer," though it is still commonly referred to as Surfer or Surfer SEO and the core product is unchanged.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$Does Surfer SEO offer a free trial?$q$, $q$There is no ongoing free plan; new subscribers get a short trial period and money-back window on the Pro plan rather than a standalone free tier.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$What is the cheapest Surfer SEO plan?$q$, $q$The entry-level Discovery plan starts at $49/month when billed annually, with limited monthly content documents and trackable pages.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$Can Surfer SEO write full articles automatically?$q$, $q$Yes, via Surfer AI, which generates draft articles from a content brief that can then be reviewed and refined inside the Content Editor.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$Does Surfer SEO track AI search visibility, not just Google rankings?$q$, $q$Yes, its AI visibility tracker monitors brand mentions in AI Overviews and chatbot answers from platforms like ChatGPT and Gemini, in addition to traditional SERP tracking.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$Content Brief Creation for Writers$q$, $q$SEO teams generate data-backed content briefs from SERP analysis so freelance or in-house writers know exactly which terms, questions, and structure to cover before drafting.$q$, $q$In-house content marketers and editorial teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$Agency Client Content Audits$q$, $q$Agencies run existing client pages through Content Audit to find quick-win optimizations and prioritize a backlog of updates across multiple accounts.$q$, $q$SEO and digital marketing agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$Affiliate and Blog Content Optimization$q$, $q$Publishers optimize individual articles against top-ranking competitors to improve organic rankings and protect ad or affiliate revenue tied to search traffic.$q$, $q$Bloggers and affiliate site owners$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$Monitoring Brand Presence in AI Answers$q$, $q$Marketing teams track how often their brand is cited in AI Overviews and chatbot responses, adjusting content to improve visibility beyond traditional search results.$q$, $q$Brand and growth marketing teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$Discovery$q$, $q$$49/month$q$, $q$Billed annually (higher rate for monthly billing)$q$, $q$["120 content documents per year","Track up to 10 pages","1 brand workspace, 1 seat","AI SEO guidelines and Surfy assistant"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$Standard$q$, $q$$99/month$q$, $q$Billed annually$q$, $q$["360 content document credits","Track up to 50 pages","25 AI visibility prompts, weekly refresh","3 seats and AI Tracker included"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$Pro$q$, $q$$182/month$q$, $q$Billed annually$q$, $q$["360 content document credits","Daily AI visibility prompt refresh across multiple platforms","5 brand workspaces","Internal linking suggestions and content gap analysis"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$Enterprise$q$, $q$Custom pricing (from roughly $999/month)$q$, $q$Annual contract$q$, $q$["Custom usage limits on all Pro features","SSO and enterprise-grade security","White-labeling for agencies","API access, priority support, and a dedicated success manager"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Surfer (rebranded "Positive Surfer" after a 2025 acquisition by Positive Group, though still widely known by its original name Surfer SEO) is a content optimization and SEO platform founded in 2017 in Wrocław, Poland. It built its reputation on a data-driven approach: scanning the pages currently ranking for a target keyword and turning that analysis into concrete, actionable on-page guidance for writers and SEO teams, rather than relying on generic best-practice checklists.$q$, $q$The platform's flagship Content Editor scores drafts in real time against dozens of on-page signals pulled from top search results, including word count, keyword usage, headings, and related terms, so writers can see exactly what separates page-one content from everything below it. Around that core editor, Surfer has built out a fuller toolkit spanning keyword research, SERP analysis, content auditing of existing pages, and AI-assisted drafting for teams that want a first draft generated automatically.$q$, $q$More recently, Surfer has expanded beyond classic Google rankings to track "AI visibility" — whether and how a brand gets cited in AI Overviews and chatbot answers from tools like ChatGPT and Gemini. This reflects a broader shift across the SEO tooling category, as vendors race to help brands stay visible while search shifts from ten blue links toward AI-generated answers, and it positions Surfer as more than a single-purpose content-scoring tool. The 2025 acquisition by Positive Group, a European SaaS group with existing email and CRM products, added resources for this expansion while the founding team stayed on to run the product.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$who-surfer-seo-is-for$q$, $q$Who Surfer SEO Is For$q$, 2, ARRAY[$q$Surfer is built for people who publish optimized content on an ongoing basis and want data behind their editorial decisions rather than guesswork. In-house content marketers and SEO specialists use it to brief writers, prioritize which existing pages to refresh, and justify content decisions with concrete competitive data instead of intuition alone.$q$, $q$SEO and content marketing agencies are a core audience: multiple brand workspaces, team collaboration, and, on higher plans, white-labeling and API access make it practical to run several client accounts from a single subscription. Freelance SEO consultants use the same features at a smaller scale to back up their recommendations with numbers a client can see for themselves.$q$, $q$Bloggers, affiliate publishers, and e-commerce content teams whose revenue depends directly on organic search traffic also fit well, since Surfer's guidance is oriented toward ranking specific pages for specific keywords rather than general brand-awareness content. Teams that already run a disciplined content calendar tend to get the most value, since the tool rewards consistent, repeated use.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Casual or infrequent publishers may find Surfer hard to justify. There is no perpetual free plan, and even the entry-level Discovery tier is priced for people producing content regularly, not for someone writing a handful of posts a year as a side project.$q$, $q$Teams working heavily in languages outside Surfer's core NLP support — English, Danish, Dutch, and Polish — will get a noticeably weaker experience, since content scoring and term suggestions are less refined outside those languages even though keyword and SERP data can be pulled for almost any market and language pair.$q$, $q$Businesses looking for a single all-in-one marketing suite spanning email, CRM, and social media alongside content should also look elsewhere. Despite now sitting inside Positive Group's broader marketing portfolio, Surfer itself remains a focused content-and-SEO tool rather than a full marketing platform, so teams wanting one login for everything will likely need to pair it with other software. Very small solo operators on tight budgets may also prefer a cheaper standalone keyword tool if they do not need the full content-scoring workflow.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At the center of the product is the Content Editor, which scores drafts in real time against competitor benchmarks and flags missing terms, structural gaps, and length issues as a writer works, whether typing directly into Surfer or pasting in a draft from Google Docs or a CMS.$q$, $q$The SERP Analyzer breaks down what is currently ranking for a keyword, including content structure, common questions searchers ask, word counts, and backlink signals, while Keyword Research surfaces related terms and search volume localized by country. Content Audit runs the same style of analysis against already-published pages to surface quick-win optimizations, and a topical mapping tool helps plan clusters of related articles around a subject.$q$, $q$Surfer also includes Surfer AI for generating full draft articles from a brief, an AI visibility tracker for monitoring brand mentions across AI Overviews and chatbot platforms, and integrations with WordPress and Google Docs so optimized content can be published or edited without leaving existing workflows. An in-app assistant, Surfy, helps users navigate the platform's growing feature set, and higher-tier plans add internal linking suggestions and content-gap analysis across an entire site.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', $q$the-surfer-seo-experience$q$, $q$The Surfer SEO Experience$q$, 2, ARRAY[$q$Day to day, using Surfer follows a fairly linear workflow: research a keyword and its SERP, generate a content brief or outline from that research, write inside the Content Editor while watching the live content score climb, and then run an audit later on to catch drift as competitors update their own pages and rankings shift.$q$, $q$The interface is generally described as clean and approachable for anyone already comfortable with basic SEO concepts, though newcomers typically need some ramp-up time to understand what the content score is actually measuring and how much weight to give it relative to their own editorial judgment and audience knowledge.$q$, $q$Documentation, the in-app Surfy assistant, and an active user community help offset that learning curve. Most reviewers note that Surfer delivers a clear, immediate feedback loop, since writers can watch their score change as they edit, which many find motivating even as SEO purists caution against optimizing purely to hit a number rather than serving the reader.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a009a42b-b701-46b1-bc27-3bc5f232d1f9', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
