INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5ac53984-b400-454f-baed-b707bfdb12ec', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3420577a-4640-4828-a64b-5afe612e65be', $q$Drag-and-drop visual analytics$q$, $q$Build charts, maps, and dashboards by dragging fields onto a canvas, with Tableau automatically generating the underlying queries and suggesting appropriate visualization types.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3420577a-4640-4828-a64b-5afe612e65be', $q$Broad data connectivity$q$, $q$Connect natively to spreadsheets, cloud data warehouses, databases, and popular SaaS applications, plus a large library of third-party and community connectors.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3420577a-4640-4828-a64b-5afe612e65be', $q$Tableau Prep$q$, $q$A dedicated tool for cleaning, shaping, and combining data from multiple sources before it reaches a dashboard, using a visual flow-based interface.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3420577a-4640-4828-a64b-5afe612e65be', $q$Calculated fields and LOD expressions$q$, $q$Create custom metrics and level-of-detail calculations to answer analytical questions that go beyond simple aggregations.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3420577a-4640-4828-a64b-5afe612e65be', $q$Governed sharing via Tableau Cloud/Server$q$, $q$Publish dashboards to a centrally managed environment with role-based permissions, certified data sources, and scheduled data refreshes.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3420577a-4640-4828-a64b-5afe612e65be', $q$Row-level security$q$, $q$Restrict what data individual users can see within a shared dashboard, so the same report can be safely distributed across teams or customers.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3420577a-4640-4828-a64b-5afe612e65be', $q$Tableau Pulse and AI-assisted insights$q$, $q$Get automated, natural-language summaries of key metrics and ask questions about data in plain English to receive relevant visualizations.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3420577a-4640-4828-a64b-5afe612e65be', $q$Mobile apps$q$, $q$View and interact with published dashboards on iOS and Android through dedicated Tableau mobile apps optimized for on-the-go access.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3420577a-4640-4828-a64b-5afe612e65be', $q$Embedding and APIs$q$, $q$Embed interactive dashboards into external websites or applications using the JavaScript API, and automate content management via the REST API.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3420577a-4640-4828-a64b-5afe612e65be', $q$Extensions and dashboard actions$q$, $q$Add interactive filtering, drill-downs, and custom extensions built by Tableau or its partner ecosystem to extend dashboard functionality.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3420577a-4640-4828-a64b-5afe612e65be', $q$Powerful, flexible visual analytics that handle complex, large-scale data exploration well$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3420577a-4640-4828-a64b-5afe612e65be', $q$Very large ecosystem of trained analysts, consultants, and community resources$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3420577a-4640-4828-a64b-5afe612e65be', $q$Strong governance and security controls suited to enterprise-wide deployments$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3420577a-4640-4828-a64b-5afe612e65be', $q$Extensive connector library covering most common data sources out of the box$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3420577a-4640-4828-a64b-5afe612e65be', $q$Mature product with a long track record and continued investment from Salesforce$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3420577a-4640-4828-a64b-5afe612e65be', $q$Per-user, role-based licensing gets expensive quickly for larger teams$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3420577a-4640-4828-a64b-5afe612e65be', $q$Requires a real learning investment to move beyond basic charts to advanced calculations$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3420577a-4640-4828-a64b-5afe612e65be', $q$No confidential free tier; the free Tableau Public option publishes data openly$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3420577a-4640-4828-a64b-5afe612e65be', $q$Performance can degrade with very large or poorly optimized data sources$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3420577a-4640-4828-a64b-5afe612e65be', $q$Feels more manual and authoring-heavy compared with newer AI-first BI tools$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3420577a-4640-4828-a64b-5afe612e65be', $q$Is Tableau free to use?$q$, $q$Tableau itself is a paid product, but it offers a free trial and a related free product called Tableau Public, which lets anyone publish visualizations openly on the web. Tableau Public is not suitable for private or confidential business data.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3420577a-4640-4828-a64b-5afe612e65be', $q$What are the main Tableau license types?$q$, $q$Tableau licenses are sold by role: Viewer (view and interact with published dashboards), Explorer (view, edit, and do limited self-service analysis), and Creator (full authoring capability). Every deployment needs at least one Creator license.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3420577a-4640-4828-a64b-5afe612e65be', $q$Does Tableau require coding skills?$q$, $q$No coding is required for core dashboard building, since Tableau uses a drag-and-drop interface. More advanced analysis, such as custom calculations or level-of-detail expressions, uses Tableau's own formula syntax rather than a general-purpose programming language.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3420577a-4640-4828-a64b-5afe612e65be', $q$Can Tableau connect to cloud data warehouses and SaaS tools?$q$, $q$Yes. Tableau includes native connectors for major cloud data warehouses, databases, spreadsheets, and popular SaaS applications, and supports additional connectors built by the community and partners.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3420577a-4640-4828-a64b-5afe612e65be', $q$How does Tableau relate to Salesforce?$q$, $q$Salesforce acquired Tableau in 2019, and Tableau now operates as Salesforce's primary analytics platform. It remains available as a standalone product and also integrates more tightly with Salesforce CRM and Data Cloud.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3420577a-4640-4828-a64b-5afe612e65be', $q$Executive and operational dashboards$q$, $q$Centralize KPIs from sales, finance, and operations into interactive dashboards that leadership can monitor and drill into without waiting on manual reports.$q$, $q$Business intelligence teams and executives$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3420577a-4640-4828-a64b-5afe612e65be', $q$Self-service data exploration$q$, $q$Give analysts and business users a governed way to explore certified data sources, answer ad hoc questions, and build their own views without needing engineering support.$q$, $q$Data analysts and business users$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3420577a-4640-4828-a64b-5afe612e65be', $q$Customer-facing and embedded analytics$q$, $q$Embed interactive dashboards into a product or customer portal using Tableau's APIs, so external users can explore their own data within a branded application.$q$, $q$Product teams and SaaS companies$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3420577a-4640-4828-a64b-5afe612e65be', $q$Enterprise reporting with row-level security$q$, $q$Distribute the same dashboard across many regions, clients, or business units while restricting each viewer to only the data relevant to them.$q$, $q$Enterprise IT and analytics governance teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('3420577a-4640-4828-a64b-5afe612e65be', $q$Viewer (Standard)$q$, $q$$15/user/month$q$, $q$Billed annually$q$, $q$["View and interact with published dashboards","Filter, drill down, and export views","Receive scheduled reports and alerts","Access via web and mobile apps"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('3420577a-4640-4828-a64b-5afe612e65be', $q$Explorer (Standard)$q$, $q$$42/user/month$q$, $q$Billed annually$q$, $q$["Everything in Viewer","Self-service exploration of certified data sources","Create and edit workbooks in a browser","Save and share personal views"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('3420577a-4640-4828-a64b-5afe612e65be', $q$Creator (Standard)$q$, $q$$75/user/month$q$, $q$Billed annually$q$, $q$["Full authoring in Tableau Desktop and web authoring","Connect to any supported data source","Build and publish new data sources and dashboards","Access to Tableau Prep for data preparation"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('3420577a-4640-4828-a64b-5afe612e65be', $q$Enterprise Edition$q$, $q$From $35 to $115/user/month depending on role$q$, $q$Billed annually$q$, $q$["Advanced management and governance controls","Enhanced security and compliance options","Data Management add-on availability","Priority support options"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3420577a-4640-4828-a64b-5afe612e65be', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Tableau is a data visualization and business intelligence platform that lets people connect to virtually any data source, build interactive dashboards, and share insights across an organization without writing code. Originally spun out of a Stanford research project on visualizing databases, the company launched its first product in 2003 and grew into one of the most recognized names in analytics software. In 2019, Tableau was acquired by Salesforce, and it now operates as Salesforce's core analytics offering, integrated with the broader Salesforce ecosystem while continuing to be sold and used as a standalone platform.$q$, $q$At its core, Tableau is built around drag-and-drop visual analysis. Users connect to spreadsheets, databases, cloud warehouses, and enterprise applications, then explore the data by dragging fields onto a canvas rather than writing SQL or scripting queries. The platform automatically suggests chart types, calculates aggregations, and renders visualizations that update live as filters and parameters change. This approach made sophisticated exploratory analysis accessible to analysts and business users who previously depended on IT or data teams to answer every question.$q$, $q$Today Tableau spans several products: Tableau Desktop for authoring, Tableau Cloud and Tableau Server for hosting and distribution, Tableau Prep for data cleaning, and Tableau Public as a free platform for publishing visualizations openly. Recent versions have layered in AI-assisted features, including natural-language querying and automated insights, positioning Tableau to compete with newer AI-native analytics tools while leaning on its large existing customer base and ecosystem of certified partners and consultants.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3420577a-4640-4828-a64b-5afe612e65be', $q$who-tableau-is-for$q$, $q$Who Tableau Is For$q$, 2, ARRAY[$q$Tableau is aimed at organizations that need to turn data spread across multiple systems into visual, shareable analysis. Business intelligence and analytics teams are the primary audience, using it to build governed dashboards that get distributed to hundreds or thousands of internal stakeholders. Because it supports row-level security, scheduled data refreshes, and centralized administration, it fits well in mid-size and large companies that need consistent reporting standards across departments.$q$, $q$Data analysts and power users who want more control than a spreadsheet but don't want to write full applications are a strong fit. Tableau's visual query model lets them iterate quickly on hypotheses, blend multiple data sources, and publish polished dashboards without engineering support. Industries with heavy reporting needs, such as finance, healthcare, retail, and higher education, are common adopters, often using Tableau alongside a data warehouse as the primary layer for exploration and executive reporting.$q$, $q$Enterprises already invested in Salesforce also benefit from tighter integration, since Tableau is now part of the Salesforce Data Cloud strategy and can surface CRM data directly in dashboards. Consultancies and analytics agencies frequently standardize on Tableau because of its large talent pool of certified practitioners, extensive training resources, and long track record, which reduces hiring and onboarding risk compared with smaller or newer BI tools.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3420577a-4640-4828-a64b-5afe612e65be', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Small teams and solo users with tight budgets may find Tableau harder to justify than lighter alternatives. Licensing is priced per user by role (Viewer, Explorer, Creator), and a deployment typically requires at least one Creator seat, so even a small rollout carries meaningful recurring cost compared with tools that offer a generous free tier or flat low-cost plans.$q$, $q$Organizations that need a fully free, self-serve BI tool for internal, non-public data should look elsewhere, since Tableau's free option, Tableau Public, publishes workbooks openly on the web and is not suited for confidential business data. Teams wanting an all-in-one product that also handles data warehousing, ETL pipelines, or embedded application development natively may find Tableau requires pairing with other tools to cover those needs.$q$, $q$Companies without any dedicated analytics owner may also struggle, since getting real value from Tableau benefits from someone who understands data modeling, calculated fields, and dashboard design principles. Teams looking for the absolute simplest, most automated AI-driven reporting experience with minimal setup may prefer newer AI-first analytics products over Tableau's more manual, visually-driven workflow.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3420577a-4640-4828-a64b-5afe612e65be', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Tableau's core strength is its drag-and-drop visual analytics engine, which lets users build bar charts, maps, scatter plots, and complex combination views by manipulating fields directly on a canvas, with the software handling the underlying query generation. This is paired with a broad library of native and third-party connectors covering spreadsheets, cloud data warehouses, databases, and SaaS applications, so teams can typically connect to their existing data stack without custom integration work.$q$, $q$Beyond visualization, Tableau includes Tableau Prep for shaping and cleaning data before analysis, calculated fields and level-of-detail expressions for custom logic, and dashboard actions that let end users filter, drill down, and navigate between views interactively. Governance features such as row-level security, permissions by role, certified data sources, and centralized content management support large-scale deployments where consistency and access control matter.$q$, $q$More recent additions include Tableau Pulse, which delivers automated, AI-generated summaries of key metrics directly to users, and natural-language capabilities that let people ask questions about their data in plain English and receive a relevant chart in response. Mobile apps for iOS and Android, an extensive REST and JavaScript API for embedding dashboards into other applications, and a large marketplace of extensions round out the platform for teams that need to go beyond out-of-the-box dashboards.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3420577a-4640-4828-a64b-5afe612e65be', $q$the-tableau-experience$q$, $q$The Tableau Experience$q$, 2, ARRAY[$q$Using Tableau typically starts in Tableau Desktop or the web authoring interface, where a user connects to a data source and is dropped into a workspace with fields listed on the side and a blank canvas in the middle. The learning curve is moderate: basic charts can be built within minutes, but mastering calculated fields, table calculations, and dashboard design takes real practice, which is why Tableau has built out extensive official training, certification programs, and a very active user community over the years.$q$, $q$Once dashboards are built, they are published to Tableau Cloud or Tableau Server, where viewers interact with them through a browser or mobile app without needing any authoring skill. This split between a more technical authoring experience and a simple consumption experience is central to how most organizations roll Tableau out, with a smaller group of Creators building content and a much larger group of Viewers and Explorers consuming and lightly interacting with it.$q$, $q$Overall, the experience feels powerful but occasionally dense, especially for newcomers comparing it with lighter, more automated modern BI tools. Performance and responsiveness are generally strong for well-modeled data, though very large or poorly optimized data sources can slow dashboard load times. Being part of Salesforce has brought steadier integration with CRM data and continued investment in AI features, while the core visual analysis workflow that made Tableau popular has remained largely consistent across versions.$q$]::text[], 4);
